import React, { useEffect } from 'react';
import './App.css';
import { useNavigate } from 'react-router-dom';

const Modal = ({ isOpen, onClose }) => { 

    const modalOc = document.querySelector('.modal_1 > li:first-child')
    modalOc.addEventListener("click" ,  clickHandler);
    function clickHandler(){

        if(true){
          window.location.href = <Diarypage />;
        }
      }
    // useNavigate는 컴포넌트 상단에서 호출해야 합니다
    if (!isOpen) return null;  // isOpen이 false일 때 모달을 렌더링하지 않음야 함
    return (
        <div className='modal'>
            <ul className='modal_1'>
               <li>
                    잘자요
               </li>
                <li>
                    애칭 설정
                </li>
                <li>
                    Diray List
                </li>
            </ul>
            <ul className='modal_2'>
                <li></li>
            </ul> 
        </div>
    );
}

export default Modal;
